function median(numbers) {
  if (!Array.isArray(numbers) || numbers.length === 0) {
    throw new Error('Input must be a non-empty array of numbers');
  }
  // Create a copy so we don’t mutate the original array
  const sorted = [...numbers].sort((a, b) => a - b);
  const mid = Math.floor(sorted.length / 2);
  if (sorted.length % 2 !== 0) {
    return sorted[mid];
  }
  // Even length – average the two middle values
  return (sorted[mid - 1] + sorted[mid]) / 2;
}

// Example usage:
// console.log(median([5, 3, 8, 1])); // 4
// console.log(median([7, 2, 9]));   // 7

Here is a concise Java implementation of binary search:

public class BinarySearch {
    public static int binarySearch(int[] arr, int target) {
        int left = 0;
        int right = arr.length - 1;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (arr[mid] == target) {
                return mid; // Target found
            } else if (arr[mid] < target) {
                left = mid + 1; // Search right half
            } else {
                right = mid - 1; // Search left half
            }
        }
        return -1; // Target not found
    }

    public static void main(String[] args) {
        int[] numbers = {1, 3, 5, 7, 9, 11, 13};
        int index = binarySearch(numbers, 7);
        System.out.println("Index of 7: " + index); // Output: 3
    }
}

